mapper.update:
UPDATE UB_MENTOR_BOARD
SET board_click = board_click + 1
WHERE mentorBoard_number = #{mentorBoardNumber}

UPDATE UB_MENTOR_BOARD
SET board_title = #{boardTitle}, board_content = #{boardContent}

WHERE mentorBoard_number = #{mentorBoardNumber}

mapper.select:

SELECT * FROM (
	SELECT ROWNUM AS rnum, subquery.*
	FROM (
		SELECT m.member_number, m.member_id, b.mentorBoard_number, b.board_title, 
			b.board_content, b.board_date, b.board_click
		FROM UB_MEMBER m JOIN UB_MENTOR_BOARD b
		ON m.member_number = b.member_number
		ORDER BY b.board_date DESC
	) subquery
) WHERE rnum BETWEEN #{startRow} AND #{endRow}
